#include <stdio.h>
#include <stdint.h>

int64_t power(int64_t base, int64_t exponent, int64_t mod) {
    int64_t result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % mod;
        }
        exponent /= 2;
        base = (base * base) % mod;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int64_t N;
        scanf("%lld", &N);
        int64_t mod = 1000000007;
        int64_t result = (power(2, N, mod) - 1 + mod) % mod;
        printf("%lld\n", result);
    }
    return 0;
}

